            aOrbiterI = (((aOrbiterI ^ aOrbiterB) ^ 0xA31DA94709F78A0AULL) ^ aPhaseDOrbiterUpdateSaltA[(((31U - aIndex) + 16U)) & S_SALT1]) ^ aNonceWordH;
