            aIngress = aIngress + RotL64(aOrbiterF, 29U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererH = aWandererH ^ ((RotL64(aPrevious, 13U) + aOrbiterH) + RotL64(aOrbiterD, 51U));
            aWandererA = aWandererA + ((RotL64(aScatter, 37U) + aOrbiterI) + RotL64(aOrbiterD, 11U));
            aWandererD = aWandererD ^ (((RotL64(aCross, 27U) + RotL64(aOrbiterE, 37U)) + aOrbiterA) + aPhaseAWandererUpdateSaltA[(((31U - aIndex) + 26U)) & S_SALT1]);
