            aOrbiterC = (aWandererF + RotL64(aPrevious, 44U)) + 0x4DA4DEA23E9B4C26ULL;
            aOrbiterJ = ((aWandererB + RotL64(aCross, 27U)) + 0x0756C10DBB750BCDULL) + aPhaseBOrbiterAssignSaltD[((aIndex + 29U)) & S_SALT1];
            aOrbiterE = (aWandererG + RotL64(aScatter, 23U)) + 0xC50B59866A936386ULL;
            aOrbiterK = ((aWandererH + RotL64(aPrevious, 37U)) + RotL64(aCarry, 13U)) + 0xB8A8C3A2F24257BAULL;
            aOrbiterG = ((aWandererE + RotL64(aCross, 42U)) + RotL64(aCarry, 23U)) + 0x49868A6180B2FBCCULL;
            aOrbiterA = (((aWandererK + RotL64(aScatter, 11U)) + RotL64(aCarry, 35U)) + 0x469484D5F4E5EC06ULL) + aPhaseBOrbiterAssignSaltC[((aIndex + 28U)) & S_SALT1];
            //
            aOrbiterD = ((aOrbiterD + aOrbiterI) + 0xE83785191C71D6E3ULL) + aPhaseBOrbiterUpdateSaltE[((aIndex + 25U)) & S_SALT1];
            aOrbiterB = ((aOrbiterB ^ aOrbiterD) ^ 0x05793AF87B1258A5ULL) ^ aPhaseBOrbiterUpdateSaltF[(((31U - aIndex) + 13U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 0xCEECBE15980E35B5ULL), 37U);
