            //
            aOrbiterJ = (aOrbiterJ + aOrbiterE) + 0x9B7C58595F088787ULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterJ) ^ 0x1A22B041E8409C62ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x478422EC3F80ADF7ULL), 53U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterD) + 0x71E8C53E6C47460CULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterK) ^ 0x7A71C06AFE073773ULL;
            aOrbiterG = RotL64((aOrbiterG * 0xAC8604B34CF81EABULL), 43U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterK) + 0x7D018EF415C74B5FULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterA) ^ 0x056AEE42BE71E40EULL;
