            aWandererJ = aWandererJ + (((RotL64(aPrevious, 46U) + RotL64(aOrbiterA, 3U)) + aOrbiterK) + RotL64(aCarry, 21U));
            aWandererC = aWandererC ^ (((RotL64(aCross, 29U) + aOrbiterE) + RotL64(aOrbiterG, 28U)) + aPhaseEWandererUpdateSaltE[(((31U - aIndex) + 21U)) & S_SALT1]);
            aWandererA = aWandererA + ((((RotL64(aScatter, 35U) + aOrbiterJ) + RotL64(aOrbiterF, 47U)) + RotL64(aCarry, 53U)) + aPhaseEWandererUpdateSaltC[((aIndex + 10U)) & S_SALT1]);
            aWandererK = aWandererK ^ ((RotL64(aCross, 11U) + aOrbiterF) + RotL64(aOrbiterA, 11U));
            aWandererB = aWandererB + ((RotL64(aPrevious, 41U) + aOrbiterK) + RotL64(aOrbiterI, 57U));
