            aOrbiterJ = ((aWandererC + RotL64(aIngress, 3U)) + 0xC9275AA7627F6D04ULL) + aPhaseCOrbiterAssignSaltD[((aIndex + 12U)) & S_SALT1];
            //
            aOrbiterC = ((aOrbiterC + aOrbiterB) + 0x559BF203B49468D5ULL) + aPhaseCOrbiterUpdateSaltD[(((31U - aIndex) + 17U)) & S_SALT1];
