            //
            aOrbiterB = (aOrbiterB + aOrbiterA) + 0x093699121FA6FCC3ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterB) ^ 0xB24979C79590AD75ULL;
            aOrbiterD = RotL64((aOrbiterD * 0xBE9661B639D39053ULL), 39U);
