            aOrbiterH = (aOrbiterH + aOrbiterJ) + 0x446F324546D3B782ULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterH) ^ 0xA69027A9670F854FULL) ^ aPhaseCOrbiterUpdateSaltF[(((31U - aIndex) + 4U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0xE63329111501B913ULL), 57U);
