            aOrbiterK = RotL64((aOrbiterK * 0xEB0BEE7EF8CD4843ULL), 21U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterH) + 0xED6122D934EDBE08ULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterC) ^ 0x38BE5D0A96488474ULL;
            aOrbiterI = RotL64((aOrbiterI * 0xE7E54A133D4F58FDULL), 51U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterC) + 0xD50D289E83B074F0ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterG) ^ 0x44DA2D2DB45BB479ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x0C8BAC2592E41481ULL), 39U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterK) + 0x4C20F369D69FACAFULL) + aPhaseEOrbiterUpdateSaltB[((aIndex + 7U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterI) ^ 0x4648C50DD5550B8BULL;
            aOrbiterF = RotL64((aOrbiterF * 0x5216549A4BFB4D11ULL), 47U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterJ) + 0xE9503EACCA56122DULL) + aPhaseEOrbiterUpdateSaltA[((aIndex + 19U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterK) ^ 0x6E44C46B4705584CULL;
            aOrbiterA = RotL64((aOrbiterA * 0x4BF399819A22F3F9ULL), 43U);
