            aWandererD = aWandererD + (((RotL64(aCross, 3U) + RotL64(aOrbiterA, 47U)) + aOrbiterK) + aPhaseEWandererUpdateSaltB[(((31U - aIndex) + 18U)) & S_SALT1]);
            aWandererK = aWandererK ^ (((RotL64(aPrevious, 40U) + aOrbiterC) + RotL64(aOrbiterG, 23U)) + aPhaseEWandererUpdateSaltA[((aIndex + 16U)) & S_SALT1]);
            aWandererB = aWandererB + (((RotL64(aIngress, 57U) + aOrbiterI) + RotL64(aOrbiterK, 42U)) + RotL64(aCarry, 3U));
            aWandererI = aWandererI ^ ((RotL64(aScatter, 53U) + RotL64(aOrbiterF, 19U)) + aOrbiterC);
            aWandererE = aWandererE + (((RotL64(aCross, 13U) + RotL64(aOrbiterD, 11U)) + aOrbiterJ) + RotL64(aCarry, 51U));
